```hcl
# 将 KMS 密钥策略限制为账户根以避免任何公共（"*"）主体
data "aws_caller_identity" "current" {}

resource "aws_kms_key" "<example_resource_name>" {
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = { AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root" } # 关键：限制为账户根以移除公共访问
        Action    = "kms:*"
        Resource  = "*"
      }
    ]
  })
}
```
